// Pull in the NOAA observation and the shared Config values.
const obsRaw = $('Get NOAA Observation').first().json;
const config = $('Config').first().json;

// Parse the NOAA response - it comes as a string in the "data" field
let obsRoot;
try {
  obsRoot = typeof obsRaw.data === 'string' ? JSON.parse(obsRaw.data) : obsRaw.data;
} catch (e) {
  obsRoot = obsRaw;
}

const obs = (obsRoot && obsRoot.properties) ? obsRoot.properties : {};

// ---- Raw NOAA readings (do not alter) ----
const tempC = (obs.temperature && obs.temperature.value != null) ? obs.temperature.value : null;
const tempF = tempC !== null ? (tempC * 9 / 5 + 32) : null;

const rh = (obs.relativeHumidity && obs.relativeHumidity.value != null) ? obs.relativeHumidity.value : null;

const windKmh = (obs.windSpeed && obs.windSpeed.value != null) ? obs.windSpeed.value : null;
const windMph = windKmh !== null ? (windKmh * 0.621371) : null;

const condition = obs.textDescription || 'Unknown';

// ---- NOAA Heat Index, used when T >= 80F and humidity is available ----
// Follows the full NWS procedure (not just the Rothfusz regression on its own):
// 1. Start with the simple approximation.
// 2. Only switch to the full Rothfusz regression (+ low/high-humidity adjustment)
//    if the average of T and the simple estimate is itself >= 80F. Skipping this
//    check makes the regression overshoot near the 80F boundary, which is the
//    likely reason this was reading a bit higher than NWS-based tools like OSHA's
//    Heat Safety Tool.
function calcHeatIndex(T, RH) {
  if (T === null || RH === null || T < 80) return null;

  const simple = 0.5 * (T + 61.0 + ((T - 68.0) * 1.2) + (RH * 0.094));
  if ((simple + T) / 2 < 80) {
    return Math.round(simple * 10) / 10;
  }

  let HI = -42.379 + 2.04901523 * T + 10.14333127 * RH - 0.22475541 * T * RH
    - 0.00683783 * T * T - 0.05481717 * RH * RH + 0.00122874 * T * T * RH
    + 0.00085282 * T * RH * RH - 0.00000199 * T * T * RH * RH;
  if (RH < 13 && T >= 80 && T <= 112) {
    HI -= ((13 - RH) / 4) * Math.sqrt((17 - Math.abs(T - 95)) / 17);
  } else if (RH > 85 && T >= 80 && T <= 87) {
    HI += ((RH - 85) / 10) * ((87 - T) / 5);
  }
  return Math.round(HI * 10) / 10;
}

// ---- NWS Wind Chill (2001 formula), used when T <= 50F and wind >= 3 mph ----
function calcWindChill(T, V) {
  if (T === null || V === null || T > 50 || V < 3) return null;
  const WC = 35.74 + 0.6215 * T - 35.75 * Math.pow(V, 0.16) + 0.4275 * T * Math.pow(V, 0.16);
  return Math.round(WC * 10) / 10;
}

const heatIndex = calcHeatIndex(tempF, rh);
const windChill = calcWindChill(tempF, windMph);

// ---- Feels Like: Heat Index > Wind Chill > Actual Temp ----
let feelsLike;
if (heatIndex !== null) feelsLike = heatIndex;
else if (windChill !== null) feelsLike = windChill;
else feelsLike = tempF;

const riskValue = feelsLike !== null ? Math.round(feelsLike * 10) / 10 : null;

// ---- Zone ----
let zone = 'UNKNOWN';
if (riskValue !== null) {
  if (riskValue <= 90) zone = 'GREEN';
  else if (riskValue <= 103) zone = 'YELLOW';
  else if (riskValue <= 115) zone = 'RED';
  else zone = 'BLACK';
}

return [{
  json: {
    temperature: tempF !== null ? Math.round(tempF * 10) / 10 : null,
    feelsLike: feelsLike !== null ? Math.round(feelsLike * 10) / 10 : null,
    heatIndex,
    windChill,
    humidity: rh !== null ? Math.round(rh * 10) / 10 : null,
    wind: windMph !== null ? Math.round(windMph * 10) / 10 : null,
    condition,
    riskValue,
    zone,
    updated: new Date().toISOString(),
    firebaseBaseUrl: config.firebaseBaseUrl,
    firebaseAuth: config.firebaseAuth,
    fromEmail: config.fromEmail,
    recipient1: config.recipient1,
    recipient2: config.recipient2
  }
}];

// $input here is the raw previous-zone value read from Firebase (a plain string, or null on first run).
const current = $('Calculate Feels Like & Risk').first().json;
let previousZone = $input.first().json.data;

// Firebase returns the raw value as a string (e.g. "GREEN") or null if the path doesn't exist yet.
// Strip quotes if Firebase wrapped it.
if (typeof previousZone === 'string') {
  previousZone = previousZone.replace(/^"|"$/g, '');
}
if (typeof previousZone !== 'string' || previousZone === 'null') previousZone = null;

// Only treat it as a "change" if we had a real previous value that differs.
// This avoids firing a false alert on the very first run.
const zoneChanged = previousZone !== null && previousZone !== current.zone;

// Check if we are in quiet hours (21:00 to 05:00 Mountain Time)
const now = new Date();
const hour = now.getHours(); // Local hour in the server timezone
const inQuietHours = hour >= 21 || hour < 5;

return [{
  json: {
    ...current,
    previousZone: previousZone || current.zone,
    zoneChanged,
    inQuietHours,
    currentHour: hour
  }
}];

const current = $('Compare Zones').first().json;
const pendingData = $input.first().json.data;

let hasPending = false;
let pendingAlert = null;

if (pendingData && typeof pendingData === 'object' && pendingData.hasPending === true) {
  hasPending = true;
  pendingAlert = pendingData;
}

return [{
  json: {
    ...current,
    hasPending,
    pendingAlert
  }
}];

const pointsData = $input.first().json.data;
const parsed = typeof pointsData === 'string' ? JSON.parse(pointsData) : pointsData;
const forecastUrl = parsed.properties.forecastHourly;

return [{ json: { forecastUrl } }];

const forecastRaw = $input.first().json.data;
const config = $('Forecast Config').first().json;

let forecastData;
try {
  forecastData = typeof forecastRaw === 'string' ? JSON.parse(forecastRaw) : forecastRaw;
} catch (e) {
  forecastData = forecastRaw;
}

const periods = forecastData.properties?.periods || [];

function calcHeatIndex(T, RH) {
  if (T === null || RH === null || T < 80) return null;
  let HI = -42.379 + 2.04901523 * T + 10.14333127 * RH - 0.22475541 * T * RH
    - 0.00683783 * T * T - 0.05481717 * RH * RH + 0.00122874 * T * T * RH
    + 0.00085282 * T * RH * RH - 0.00000199 * T * T * RH * RH;
  if (RH < 13 && T >= 80 && T <= 112) {
    HI -= ((13 - RH) / 4) * Math.sqrt((17 - Math.abs(T - 95)) / 17);
  } else if (RH > 85 && T >= 80 && T <= 87) {
    HI += ((RH - 85) / 10) * ((87 - T) / 5);
  }
  return Math.round(HI * 10) / 10;
}

function calcWindChill(T, V) {
  if (T === null || V === null || T > 50 || V < 3) return null;
  const WC = 35.74 + 0.6215 * T - 35.75 * Math.pow(V, 0.16) + 0.4275 * T * Math.pow(V, 0.16);
  return Math.round(WC * 10) / 10;
}

function getZone(feelsLike) {
  if (feelsLike === null) return 'UNKNOWN';
  if (feelsLike <= 90) return 'GREEN';
  if (feelsLike <= 103) return 'YELLOW';
  if (feelsLike <= 115) return 'RED';
  return 'BLACK';
}

const zoneChanges = [];
let currentZone = null;

for (const period of periods) {
  const time = new Date(period.startTime);
  const hour = time.getHours();

  // Only include periods during alert hours (05:00-20:59)
  if (hour < 5 || hour >= 21) continue;

  const tempF = period.temperature;
  const rh = period.relativeHumidity?.value || null;
  const windStr = period.windSpeed || '0 mph';
  const windMph = parseFloat(windStr);

  const heatIndex = calcHeatIndex(tempF, rh);
  const windChill = calcWindChill(tempF, windMph);

  let feelsLike;
  if (heatIndex !== null) feelsLike = heatIndex;
  else if (windChill !== null) feelsLike = windChill;
  else feelsLike = tempF;

  const zone = getZone(feelsLike);

  if (zone !== currentZone) {
    const timeStr = time.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
    zoneChanges.push({ zone, time: timeStr, feelsLike, temperature: tempF });
    currentZone = zone;
  }
}

return [{
  json: {
    zoneChanges,
    fromEmail: config.fromEmail,
    recipient1: config.recipient1,
    recipient2: config.recipient2
  }
}];
